var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"평화로운 유원지군요. 동물원이 들어섰다더니 구경거리도 아주 많네요.","JPN":"穏やかな雰囲気の遊園地ですね。動物園ができたと聞いたのですが、見どころも満載です。","ENG":"It’s a peaceful amusement park. There being a zoo, I believe there’re lots to see.","TWN":"真是悠閒的遊樂園，動物園蓋起來後，有很多可以逛的呢。"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"즐거워 보이는구나.","JPN":"楽しそうじゃな。","ENG":"You look happy.","TWN":"感覺好好玩喔。"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"후후, 여긴 깜찍한 볼거리가 있습니다, 주인님.","JPN":"フフ、ここではかわいいものを見物できますよ。ご主人様。","ENG":"Ha ha, look at the cute animals here, Mistress.","TWN":"呵呵，主人您看，這個好可愛。"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"이것 보십시오. 바닥에 느긋하게 달라붙어서 이빨을 드러낸 모습이 사랑스럽지 않습니까?","JPN":"見てください。のんびりと地面に寝転んで歯を剥きだした姿、愛おしくありませんか？","ENG":"Look here. Lying on the floor showing its teeth... Doesn’t it look lovely?","TWN":"您看牠趴在地上露出牙齒的模樣，是不是很可愛？"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"흐음, 그러냐?","JPN":"ふむ、そうか？","ENG":"Hmm, does it?","TWN":"嗯哼，是嗎？"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"네가 악어를 좋아하는 건 처음 알았구나.","JPN":"其方がワニ好きだとは、初めて知ったぞ。","ENG":"I didn’t know you had a liking for crocodiles.","TWN":"原來你喜歡鱷魚喔。"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"그러게.","JPN":"そうだな。","ENG":"I didn’t know either.","TWN":"是喔？"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"까짓 거, 돈 받으면 저것도 몇 마리 사지 뭐.","JPN":"そんなに金をもらえるんなら、あれも何匹か買おうじゃないか。","ENG":"I guess I’ll get a few crocodiles once I get the money.","TWN":"小意思，等我賺到錢之後買幾隻送哥哥！"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"잠깐만요, 감독님.","JPN":"待ってください、監督。","ENG":"Wait.","TWN":"我說導演，"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"왜 유원지죠? 제가 받은 대본에는 이런 장소가 없었는데요?","JPN":"なんで遊園地なんですか？　私がもらった台本にこんな場所はなかったはずですけど。","ENG":"Why are we at an amusement park? There wasn’t a place like this in the script.","TWN":"為什麼要來遊樂園？我拿到的劇本裡完全沒有提到遊樂園啊？"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"그야 리허설에 없던 내용이기 때문이지.","JPN":"そりゃそうだ、リハーサルにはなかった内容だからな。","ENG":"It’s because this isn’t part of the rehearsal.","TWN":"因為這不在排演的內容裡。"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"그리고 이번 촬영분은 다음 시즌의 예고편으로 사용될 거야.","JPN":"そして今回の撮影は次のシーズンの予告編として使われる。","ENG":"What we’re filming here will be used as a trailer for the next season.","TWN":"而且今天拍攝的內容，會直接拿來當作預告片。"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"네? 그렇다는 건 이번 씬이…?","JPN":"えっ？　それはつまりこのシーンが……？","ENG":"What? That means this scene is...?","TWN":"什麼？意思就是…？"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"리허설이 아닌 진짜 촬영이라는 뜻이군요.","JPN":"リハーサルではなく、本番ということですね。","ENG":"Not part of the rehearsal, but a real shoot.","TWN":"今天不是排演，是正式拍攝。"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"예정엔 없었지만 예술이란 원래 뜻밖의 상황에서 탄생하는 법이니까.","JPN":"予定にはなかったけど、芸術とは意外な状況から誕生するものだからな。","ENG":"It wasn’t planned, but as you know, art is created in the spur of the moment!","TWN":"雖然不在計畫之內，不過藝術本來就是在出其不意的情況下產生的。"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"좋아요. 자연스러운 로맨스 연기 실력을 보겠다는 거죠?","JPN":"わかりました。自然なロマンス演技の実力を見るってことですよね？","ENG":"All right. So you’re looking for natural romance acting skills, right?","TWN":"好吧，意思就是要自然地展現浪漫的演技是吧？"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"차라리 잘 됐네요. 순수한 연기라면 내가 저 여자한테 질 리는 없을 테니까.","JPN":"むしろよかったです。演技力なら、私があの女に負けるわけないですから。","ENG":"Maybe it’s better this way. I won’t lose to that girl when it comes to pure acting skills.","TWN":"那正好！單純比演技的話，我可不會輸她！"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L28_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"까불지 마라. 뭉개버린다.","JPN":"調子に乗るな。ぶっ潰すぞ。","ENG":"Don’t tread on me or I’ll smush you.","TWN":"少囂張，我可不會手下留情！"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"그런다고 누가 쫄 것 같아? 법정 가고 싶으면 쳐보시던가.","JPN":"そんなこと言われたって怖くないわ。訴えられたいなら、殴ってみなさいよ。","ENG":"You think I’ll freak out? Hit me if you can. We’ll meet at court.","TWN":"你以為這樣我就會怕嗎？敢打我試試看，我會告到你上法院！"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"아서라, 의뢰인. 저 시종 녀석은 농담을 할 줄 모른단다.","JPN":"よせ、依頼人。あの僕は冗談が通じぬ。","ENG":"Stop it, you. My servant doesn’t know how to make jokes.","TWN":"委託人，勸你少說兩句，我的僕人會當真的。"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"…흥, 저런 깡패가 무슨 연기를 하겠다고.","JPN":"……フン、あんなチンピラが演技だなんて。","ENG":"...Hmpf, that gangster will never be good at acting.","TWN":"…哼，那個女流氓懂什麼演戲！"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_HATE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"하지만 상대 배역인 니콜라스씨가 부재중인 지금 예고편을 찍는 건 어렵지 않습니까?","JPN":"ですが相手のニコラスさんが不在ですと、今予告編を撮影するのは難しいのではないですか？","ENG":"But we can’t film the trailer without Nicholas here, can we?","TWN":"不過演出男主角的尼可拉斯不是不在嗎？那要怎麼拍預告呢？"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"하하, 그건 걱정 마. 고작 그런 이유로 간만에 찾은 귀한 인재를 돌려보낼 순 없지.","JPN":"ハハッ、それは心配するな。たかがそんな理由でせっかく見つけた貴重な人材を帰らせるわけにはいかないだろう。","ENG":"Ha ha, you don’t need to worry about that. I can’t just send back a person with such talent.","TWN":"哈哈，放心吧！我怎麼可能因為這種小事，就放走好不容易才找到的人才呢！"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"STAFF_NPC_DRAMA_NULL","text":{"KOREA":"감독님! 니콜라스 씨가 지금 막 공항에 도착하셨다고 합니다.","JPN":"監督！　ニコラスさんが今空港に着いたみたいです。","ENG":"Mr. Director! Mr. Nicholas just arrived at the airport.","TWN":"導演！尼可拉斯剛到機場。"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_NPC_DRAMA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"뭐가 이렇게 굼떠? 파벨라가 기다리잖아! 좀 서두르라고 해!","JPN":"ちょっと、それじゃあ遅いんだよ！　ファヴェーラが待ってるだろう！　急げと言え！","ENG":"What’s taking him so long? Fabella is waiting! Tell him to hurry!","TWN":"才剛到機場？帕貝拉在等他欸！叫他快一點！"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_NPC_DRAMA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"니, 니콜라스?!","JPN":"に、ニコラス！？","ENG":"N-Nicholas?!","TWN":"尼…尼可拉斯？！"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"이거 실화인가? 대배우 니콜라스가 직접 이곳으로…?","JPN":"うそ、本当？　大俳優ニコラスが、直接ここに……？","ENG":"Can this be true? The great actor Nicholas is coming all the way here...?","TWN":"是真的嗎？男神尼可拉斯要來這裡…？"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"나와 함께 촬영하기 위해서…?","JPN":"私と一緒に撮影するために……？","ENG":"To film with me...?","TWN":"和我一起拍片…？"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_LAUGH"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"GUEST_NPC_PARK_A","text":{"KOREA":"내가 제대로 보고 있는 거 맞는 거야?","JPN":"あれ、夢じゃないわよね？","ENG":"Am I seeing this right?","TWN":"我沒眼花吧？"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CROWD_NOISE"},{"id":"L47_1","type":"dialog","speaker":"GUEST_NPC_PARK_B","text":{"KOREA":"맞지? 유혹의 함교에 나오는 배우!","JPN":"本物？　誘惑の艦橋に出演してる俳優！","ENG":"It’s him! That guy from The Bridge of Seduction!","TWN":"沒錯吧？那是誘惑的艦橋的演員吧？！"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"GUEST_NPC_PARK_C","text":{"KOREA":"세상에! 그 니콜라스 캐비닛이잖아! 갑자기 유원지에는 어쩐 일로 왔대?","JPN":"まあ！　あのニコラス・キャビネットじゃない！　なんでいきなり遊園地に来たのかな？","ENG":"Oh my goodness! It really is \\"the\\" Nicholas Cabinet! Why is he here at the amusement park?","TWN":"天啊！那不是尼可拉斯嗎？他怎麼會來遊樂園？"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"GUEST_NPC_PARK_B","text":{"KOREA":"사진 같이 찍어 달라고 해볼까?","JPN":"一緒に写真撮ってもらう？","ENG":"Should I ask to take a picture together?","TWN":"要去找他拍照嗎？"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"GUEST_NPC_PARK_A","text":{"KOREA":"니콜라스 씨! 팬이에요!","JPN":"ニコラスさん！　あなたのファンです！","ENG":"Oh, Nicholas! I’m a huge fan!","TWN":"尼可拉斯！我是你的粉絲！"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CROWD"},{"id":"L1_1","type":"dialog","speaker":"GUEST_NPC_PARK_C","text":{"KOREA":"당신이 나온 작품은 다 챙겨봤어요! 유혹의 함교에서도 완전 최고예요!","JPN":"あなたが出演した作品は全部見ました！　誘惑の艦橋も、もう最高です！","ENG":"I’ve seen all your works! You’re the best even in The Bridge of Seduction!","TWN":"你拍的戲我都有看喔！你在誘惑的艦橋裡演得超好的！"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_MAN","text":{"KOREA":"하하, 감사합니다. 다음 시즌도 많은 관심 부탁드려요.","JPN":"ハハッ、ありがとうございます。次のシーズンもよろしくお願いします。","ENG":"Ha ha, thank you. Hope you show some love for the next season as well.","TWN":"哈哈，謝謝，下一季也要記得收看喔。"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ACTOR_NPC_DRAMA_MAN","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_MAN","text":{"KOREA":"…피곤하군. 모처럼의 휴가를 이런 식으로 날리다니.","JPN":"……疲れた。せっかくのバカンスが台無しになったな。","ENG":"...I’m tired. I can’t believe I wasted my vacation like this.","TWN":"…真累人，難得的假期就這樣泡湯了。"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ACTOR_NPC_DRAMA_MAN","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"왔나? 쉬고 있을 때 불러서 미안하군.","JPN":"来たか？　休みの途中に呼び出して悪いな。","ENG":"You’re here. Sorry to call you while you were on vacation.","TWN":"你來啦？真是不好意思，在你休假的時候找你過來。"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ACTOR_NPC_DRAMA_MAN","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_MAN","text":{"KOREA":"아, 괜찮습니다. 감독님이 부르시면 언제라도 와야죠.","JPN":"いえ、大丈夫です。監督に呼ばれたんなら、いつでも駆けつけてきますよ。","ENG":"Ah, it’s all right. I should always come when you need me.","TWN":"沒關係的，只要導演找我，我一定會立刻飛奔過來。"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ACTOR_NPC_DRAMA_MAN","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"이번 리허설에 굉장한 거물이 왔어. 자네에게도 소개시켜줘야겠다 싶어서 말이야.","JPN":"今回のリハーサルにとんでもない大物が現われたんだよ。君には紹介しとかないと思ってさ。","ENG":"We have a great talent at the rehearsal. I thought I should introduce her to you.","TWN":"這次的試鏡來了個怪物新人，所以想說一定要介紹給你認識一下。"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ACTOR_NPC_DRAMA_MAN","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_MAN","text":{"KOREA":"리허설?","JPN":"リハーサル？","ENG":"Rehearsal?","TWN":"試鏡？"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ACTOR_NPC_DRAMA_MAN","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_MAN","text":{"KOREA":"아, 파벨라 역은 결국 다시 뽑기로 했었죠.","JPN":"あっ、ファヴェーラ役は結局新しい女優を選ぶことになったんでしたよね。","ENG":"Ah, yes. We decided to pick another person for Fabella’s role.","TWN":"對吼，帕貝拉的角色要重新選角。"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ACTOR_NPC_DRAMA_MAN","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"그렇지. 엠마 양은 부상 때문에 한동안 출연이 어렵게 됐으니 말이야.","JPN":"そうだ。エマさんは怪我でしばらく出演できなくなったし。","ENG":"Right. Miss Emma’s injury has made it difficult for her to be on the show for a while.","TWN":"是啊，畢竟艾瑪受傷後，可能有好一陣子都無法演出。"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ACTOR_NPC_DRAMA_MAN","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_MAN","text":{"KOREA":"안타까운 일이예요. 엠마 양이 함선문을 격파하는 씬에서 CG없이 가겠다고 했을 때, 저희가 말렸어야 했는데 말이죠.","JPN":"残念です。エマさんが艦船の扉を撃破するシーンをCGなしでやると言った時、俺たちが止めるべきでした。","ENG":"What a pity. We should’ve stopped her when she said she wanted to break the gate of the ship herself without using CGI.","TWN":"真是遺憾，艾瑪當初說不靠CG，要親自上場擊破艦船門時，我們應該阻止她的。"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ACTOR_NPC_DRAMA_MAN","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"그 일은 나도 유감이야. 카운터 아카데미 출신이니까 혹시나 싶었는데, 역시 D급에겐 무리였지.","JPN":"それは私も残念だった。カウンターアカデミー出身だからもしやと思ったが、やっぱりD級には無理だったな。","ENG":"I feel sad for her, too. Though she was from the Counter Academy, it was too much for a Grade D.","TWN":"那件事我也很遺憾，我本來以為她是制裁者學院出來的，應該沒問題，沒想到對D級來說還是有點勉強。"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ACTOR_NPC_DRAMA_MAN","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"어쨌건. 그래서 재촬영을 하게 돼서 니콜라스 씨를 부르게 됐어.","JPN":"とにかく。それで撮り直しってわけで、ニコラスさんを呼んだんだ。","ENG":"Anyway, I called you in because we need to film a retake.","TWN":"總之現在要重拍，所以才把你也找來。"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ACTOR_NPC_DRAMA_MAN","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_MAN","text":{"KOREA":"리허설 당일날 촬영 재개라니. 어지간히 감독님 마음에 든 모양이군요.","JPN":"リハーサル当日に撮影再開なんて、監督、本当に気に入ったようですね。","ENG":"Filming on the day of the rehearsal. I guess you liked her a lot.","TWN":"竟然排演當天就要重新開拍，看來導演很滿意喔？"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ACTOR_NPC_DRAMA_MAN","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_MAN","text":{"KOREA":"그래봐야 엠마 양만큼 파벨라 역을 소화하긴 어렵겠지만…","JPN":"でも、エマさんほどファヴェーラ役を上手く演じるのは無理でしょうけど……","ENG":"But still, there won’t be anyone to replace Miss Emma...","TWN":"不過要像艾瑪把帕貝拉詮釋得那麼好，可能有難度…"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"어이, 감독!","JPN":"おい、監督！","ENG":"Hey, Director!","TWN":"喂，導演！"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_MAN","text":{"KOREA":"음?","JPN":"うん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"이 인간들이 자꾸 나한테 이상한 걸 들이미는데, 때려도 돼?","JPN":"この人間どもがアタシに変なものを突きつけてくるけど、殴っていいか？","ENG":"These humans keep sticking out strange stuff to me. Can I beat them up?","TWN":"這些人老是在我身上弄些有的沒的，我可以打人嗎？"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"STAFF_NPC_DRAMA_NULL","text":{"KOREA":"그, 그래도 촬영 들어가기 전에 분장은 하셔야…","JPN":"で、でも撮影前にメイクくらいは……","ENG":"B-but still you should put on make up before...","TWN":"上…上鏡頭總是要梳妝的嘛…"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"됐어. 배우가 괜찮다는데 억지로 메이크업을 강요할 필요는 없지.","JPN":"いい。女優がいらないって言ってるんだから、メイクを無理強いする必要はないだろう。","ENG":"It’s fine. She says it’s fine. No need to force her to put on make up.","TWN":"沒關係，既然演員不想要，那就沒必要強迫她。"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_MAN","text":{"KOREA":"(저 감독 양반이 배우한테 양보를 하다니… 대체 얼마나 마음에 든 거지?)","JPN":"(あの監督が女優に合わせるだなんて……どれだけ気に入ったんだ？)","ENG":"(The director’s giving up for an actress? How much does he even like her?)","TWN":"(導演這傢伙竟然會讓步…到底是有多滿意她？)"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ACTOR_NPC_DRAMA_MAN","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_MAN","text":{"KOREA":"(마스크는 괜찮긴 한데. 야만인처럼 너무 절제가 없어 보인단 말이야.)","JPN":"(顔はいいけど。野蛮人みたいに節度なんて無さそうなんだよな。)","ENG":"(Her looks are fine, but she looks like she won’t have moderation.)","TWN":"(長得是還可以啦，但行為舉止像野蠻人一樣沒規矩。)"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"니콜라스 씨가 저 여자를 유심히 쳐다보고 있잖아?","JPN":"ニコラスさんがあの女をじっと見てる？","ENG":"Mr. Nicholas is staring at the girl?","TWN":"尼可拉斯幹嘛一直盯著她看？"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"흥. 저렇게 별나게 생겼으니 눈이 가는 것도 당연하지.","JPN":"フンッ。あんな変な顔してるし、目が行くのも無理はないわ。","ENG":"Hmpf! No wonder he’s staring. She’s so odd looking.","TWN":"哼，她長得那麼特殊，多看兩眼也是可以理解的。"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_PRIDE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"어차피 나랑 연기로 호흡을 맞추고 나면 저런 경박한 깡패에게 관심 가질 일은 없을 테니까.","JPN":"どうせ私と一緒に演じたら、あんな軽薄なチンピラに興味を持つことなんてないはずよ。","ENG":"After acting with me, he won’t be interested in such a gangster.","TWN":"反正和我演完戲後，他就不會對那個輕浮的女流氓感興趣了。"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_MAN","text":{"KOREA":"미안해, 파벨라. 하지만 난 약속했어. 프레데리카가 돌아올 때까지 기다리기로 말이야.","JPN":"ごめん、ファヴェーラ。でも俺は約束したんだ。フレデリカが帰って来るまで待つと。","ENG":"I’m sorry, Fabella. But I made a promise. A promise that I’d wait until Frederica comes back.","TWN":"帕貝拉，對不起，我有答應過弗蕾德莉卡，我會等她回來。"},"stage":{"bg":"PARK","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ACTOR_NPC_DRAMA_MAN","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"기다릴 필요 없어.","JPN":"待つ必要なんてない。","ENG":"There’s no need to wait.","TWN":"你不用等她了。"},"stage":{"bg":"PARK","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ACTOR_NPC_DRAMA_MAN","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"당신은 사령부가 그 여자를 우주의 전쟁터로 내보낸 게 정말 우연이라고 생각해?","JPN":"あんたは本当にたまたま司令部があの女を宇宙の戦場に行かせたと思うのか？","ENG":"You think the Operations Command sent that woman to outer space by coincidence?","TWN":"你當真以為司令部派她去宇宙的戰場只是巧合嗎？"},"stage":{"bg":"PARK","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ACTOR_NPC_DRAMA_MAN","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_MAN","text":{"KOREA":"설마…? 당신이 어떻게 그런 짓을!","JPN":"まさか……？　君、なんてことを！","ENG":"What...? How dare you!","TWN":"該不會…？你怎麼可以這麼做！"},"stage":{"bg":"PARK","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ACTOR_NPC_DRAMA_MAN","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"로미오. 내가 말했지?","JPN":"ロミオ。言っただろう？","ENG":"Romeo. I told you.","TWN":"羅密歐，我說過，"},"stage":{"bg":"PARK","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ACTOR_NPC_DRAMA_MAN","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"난 가지기로 한 건 무조건 가진다고.","JPN":"アタシはほしいものは絶対手に入れるって。","ENG":"Once I want it, I have to get it.","TWN":"只要是我想要的東西，就一定要得到手！"},"stage":{"bg":"PARK","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ACTOR_NPC_DRAMA_MAN","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_MAN","text":{"KOREA":"그런 식으로 협박한다고 해서 진짜 사랑을 얻을 수 있을 것 같아?","JPN":"そんなふうに脅して、本物の愛を手に入れられると思うのか？","ENG":"You think you’ll be able to win my love by threatening me like that?","TWN":"你以為這樣威脅我，就可以得到你想要的愛情嗎？"},"stage":{"bg":"PARK","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ACTOR_NPC_DRAMA_MAN","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_MAN","text":{"KOREA":"당신이란 여자는 정말 최악이군!","JPN":"君という女は本当に最悪だ！","ENG":"You’re the worst!","TWN":"像你這種女人真的是非常糟糕！"},"stage":{"bg":"PARK","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ACTOR_NPC_DRAMA_MAN","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"마음대로 생각해. 하지만 그 여자가 돌아오길 원한다면 결정해야 할 거야.","JPN":"どう思われたっていい。だが、あの女に帰ってきてほしければ決めろ。","ENG":"Think as you wish. But if you want the woman to come back, you’ll have to make a decision.","TWN":"隨你怎麼想，不過如果你希望她回來，你就必須做出決定。"},"stage":{"bg":"PARK","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ACTOR_NPC_DRAMA_MAN","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"날 사랑할지. 아니면 그 여자를 머나먼 우주에서 전쟁미아가 되도록 내버려둘지.","JPN":"アタシのことを愛するか、それともあの女を遠い宇宙の戦争の中で彷徨わせるか。","ENG":"Whether to love me, or to leave that woman alone lost in outer space.","TWN":"你是要愛我？還是讓她在遙遠的宇宙裡成為戰爭孤兒？"},"stage":{"bg":"PARK","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ACTOR_NPC_DRAMA_MAN","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"컷!","JPN":"カット！","ENG":"Cut!","TWN":"Cut！"},"stage":{"bg":"PARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_SNAP"},{"id":"L49_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_MAN","text":{"KOREA":"후우.","JPN":"ふう。","ENG":"Phew.","TWN":"呼～"},"stage":{"bg":"PARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ACTOR_NPC_DRAMA_MAN","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"고생하셨어요, 니콜라스 씨! 음료 좀 드세요!","JPN":"お疲れ様です、ニコラスさん！　これ、飲んでください！","ENG":"Thank you, Mr. Nicholas! Have something to drink!","TWN":"辛苦了，尼可拉斯！喝點飲料！"},"stage":{"bg":"PARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ACTOR_NPC_DRAMA_MAN","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_MAN","text":{"KOREA":"아, 고마워요. 친절하시네요.","JPN":"あっ、どうも。ありがとうございます。","ENG":"Oh, thank you. You’re so kind.","TWN":"喔，謝謝你，你真客氣。"},"stage":{"bg":"PARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ACTOR_NPC_DRAMA_MAN","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"어때요, 감독님? 이 정도면 본방으로 내보내도 손색없죠?","JPN":"どうですか、監督。このくらいなら、本番に出してもいいでしょう？","ENG":"What do you think? Don’t you think it’s enough to make it to the final cut?","TWN":"導演，怎麼樣？剛才演的應該完全可以拿來播出吧？"},"stage":{"bg":"PARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_PRIDE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"흐음… 확실히 나쁘진 않았군.","JPN":"ふむ……確かに悪くはなかった。","ENG":"Hmm... Not bad.","TWN":"嗯…確實是還不錯。"},"stage":{"bg":"PARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"그렇죠? 굳이 다른 사람 연기는 볼 필요도 없겠죠?","JPN":"でしょう？　他の人の演技は見るまでもないですよね？","ENG":"Right? There’s no need to see how other people act.","TWN":"是不是？根本沒必要再看其他人的演出吧？"},"stage":{"bg":"PARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"하지만 완벽한 파벨라의 연기였다고 하기엔... 뭔가 부족하단 말이지.","JPN":"でも、完璧なファヴェーラの演技というには……何か足りないんだよな。","ENG":"But there was something missing... to say you were perfectly Fabella.","TWN":"不過距離我心目中完美的帕貝拉…好像還缺點什麼。"},"stage":{"bg":"PARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"네?","JPN":"えっ？","ENG":"Huh?","TWN":"什麼？"},"stage":{"bg":"PARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"전 토씨 하나 안 틀리고 대본대로 따라했어요! 이번엔 파벨라의 캐릭터에 대한 해석도 완벽했다고요!","JPN":"私は寸分の狂いもなく台本どおり演技しました！　今回はファヴェーラというキャラクターについても完璧に解釈したはずです！","ENG":"I got every single line correct! My interpretation of Fabella was perfect!","TWN":"我完全是照本演出欸！我把帕貝拉這個角色詮釋得很完美！"},"stage":{"bg":"PARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"그래, 분명 대본대로 했지.","JPN":"ああ、確かに台本どおりだった。","ENG":"Yes, you followed the script.","TWN":"嗯，你是照本演出沒錯。"},"stage":{"bg":"PARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"하지만 파벨라를 거부하던 로미오가 결국 그녀의 매력에 반한다는 걸 시청자들에게 납득시키려면... 지금의 연출만으론 부족해.","JPN":"だがファヴェーラのことを拒絶してたロミオが、結局は彼女の魅力に惚れるということを視聴者たちに納得させるためには……今の演出だけでは物足りない。","ENG":"But to let the viewers understand Romeo eventually falls in love with Fabella’s charm... We need something more.","TWN":"但是照你剛才所演的…很難說服觀眾，原本拒絕帕貝拉的羅密歐，後來怎麼又會愛上她。"},"stage":{"bg":"PARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"잠깐 쉬었다가 유마 양 차례로 넘어가자고.","JPN":"ちょっと休憩して、ユマさんの撮影に移ろう。","ENG":"Let’s move on to Miss Yuma after a short break.","TWN":"大家休息一下，等下換游馬小姐上場。"},"stage":{"bg":"PARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"하, 자기도 어떻게 해야 좋을지 모르는 주제에 거들먹거리긴.","JPN":"ハッ、自分だってどうしたらいいかわからないくせに偉そうに。","ENG":"Ugh... He’s holding his nose in the air though he doesn’t know what to do.","TWN":"哈，自己也不知道自己想要什麼，還在那邊雞蛋裡挑骨頭。"},"stage":{"bg":"PARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"역시 이대로는 안 되겠어.","JPN":"やっぱりここままじゃダメ。","ENG":"This can’t do.","TWN":"這樣不行！"},"stage":{"bg":"PARK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"이봐. 듣고 있지?","JPN":"ねえ。聞こえるよね？","ENG":"Hey. Are you listening?","TWN":"喂，有聽到嗎？"},"stage":{"bg":"PARK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"지금부터 오퍼레이션 마다가스카를 실행한다.","JPN":"今からオペレーション・マダガスカルを実行するわ。","ENG":"Commencing Operation Madagascar.","TWN":"立刻執行馬達加斯加計畫！"},"stage":{"bg":"PARK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MERCENARIES_NPC_SUPPLEMENT_FALLEN","text":{"KOREA":"옙, 분부대로 합죠.","JPN":"へいっ、仰せのとおりいたしましょう。","ENG":"As you command.","TWN":"是，遵命！"},"stage":{"bg":"PARK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MERCENARIES_NPC_SUPPLEMENT_FALLEN","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_PHONE"}]`);export{e as default};